class Solution:
    def outerTrees(self, trees):
        pts = [tuple(p) for p in trees]
        n = len(pts)
        if n <= 3:
            return [list(p) for p in set(pts)]
        def cross(o, a, b):
            return (a[0] - o[0]) * (b[1] - o[1]) - (a[1] - o[1]) * (b[0] - o[0])
        on_hull = set()
        for i in range(n):
            for j in range(n):
                if i == j:
                    continue
                a = pts[i]
                b = pts[j]
                pos = neg = False
                ok = True
                for k in range(n):
                    if k == i or k == j:
                        continue
                    c = cross(a, b, pts[k])
                    if c > 0:
                        pos = True
                    elif c < 0:
                        neg = True
                    if pos and neg:
                        ok = False
                        break
                if ok:
                    minx, maxx = min(a[0], b[0]), max(a[0], b[0])
                    miny, maxy = min(a[1], b[1]), max(a[1], b[1])
                    for k in range(n):
                        c = pts[k]
                        if cross(a, b, c) == 0 and minx <= c[0] <= maxx and miny <= c[1] <= maxy:
                            on_hull.add(c)
        return [list(p) for p in on_hull]

